/// <summary>
///
/// </summary>
public void close()
{
    FormDataSource ds;
    super();

    ds = element.args().record().dataSource();
    ds.research(true);
}

/// <summary>
///
/// </summary>
/// <param name = "_append"></param>
public void create(boolean _append = false)
{
    super(_append);

    ETGBinJournalLine       ETGBinJournalLine;

    select ETGBinJournalLine where ETGBinJournalLine.RecId == ETGBinLotLine.BinJournalLine;

    ETGBinLotLine.Transdate = ETGBinJournalLine.TransDate;
    ETGBinLotLine.ItemId = ETGBinJournalLine.ItemId;       
    ETGBinLotLine.Configuration = ETGBinJournalLine.Configuration;
    ETGBinLotLine.Size = ETGBinJournalLine.size;
    ETGBinLotLine.Colour = ETGBinJournalLine.Colour;
    ETGBinLotLine.Style = ETGBinJournalLine.Style;
    ETGBinLotLine.SiteId = ETGBinJournalLine.SiteId;
    ETGBinLotLine.Warehouse = ETGBinJournalLine.Warehouse;
    ETGBinLotLine.Location = ETGBinJournalLine.Location;
    ETGBinLotLine.ToBatch = ETGBinJournalLine.ToBatch;
    ETGBinLotLine.FromInventSerialId = ETGBinJournalLine.InventSerialId;

}

/// <summary>
///
/// </summary>
public void write()
{
    super();

    ETGBinJournalLine   ETGBinJournalLine;
    ETGBinLotLine       ETGBinLotLinesum;            

    select ETGBinJournalLine where ETGBinJournalLine.RecId == ETGBinLotLine.BinJournalLine;
    select sum(lotqty) from  ETGBinLotLinesum where ETGBinLotLinesum.BinJournalLine == ETGBinLotLine.BinJournalLine;

    if(ETGBinJournalLine.RecId)
    {
        ttsbegin;
        ETGBinJournalLine.selectForUpdate(true);
        ETGBinJournalLine.FGRNQty = ETGBinLotLinesum.LotQty;
        ETGBinJournalLine.modifiedField(fieldNum(ETGBinJournalLine,FGRNQty));
        ETGBinJournalLine.doUpdate();
        ttscommit;               
    }
}

/// <summary>
///
/// </summary>
/// <returns></returns>
public int active()
{
    int ret;

    ret = super();

    boolean  Serialenable,FromSerialenable;

    Serialenable=   ecoResTrackingDimensionGroupFldSetup::findByDimensionGroupFieldId(InventTable::find(ETGBinLotLine.ItemId).trackingDimensionGroup(), fieldNum(InventDim,InventSerialId)).IsActive;
    ETGBinLotLine_ds.object(fieldNum(ETGBinLotLine,InventSerialId)).allowEdit(Serialenable);

    FromSerialenable=   ecoResTrackingDimensionGroupFldSetup::findByDimensionGroupFieldId(InventTable::find(ETGBinLotLine.ItemId).trackingDimensionGroup(), fieldNum(InventDim,InventSerialId)).IsActive;
    ETGBinLotLine_ds.object(fieldNum(ETGBinLotLine,FromInventSerialId)).allowEdit(FromSerialenable);

    ETGBinLotLine_ds.allowEdit(ETGBinLotLine.TransferJRNId == "");
    ETGBinLotLine_ds.allowDelete(ETGBinLotLine.TransferJRNId == "");

    ETGBinJournalLine       ETGBinJournalLine;

    select ETGBinJournalLine where ETGBinJournalLine.RecId == ETGBinLotLine.BinJournalLine;

    if(ETGBinJournalLine.RecId && ETGBinJournalLine.BinFGRNLocked == NoYes::Yes)
    {
        ETGBinLotLine_ds.allowCreate(false);
        ETGBinLotLine_ds.allowDelete(false);
        ETGBinLotLine_ds.allowEdit(false);                
        ETGLotInfoDetails_ds.allowCreate(false);
        ETGLotInfoDetails_ds.allowDelete(false);
        ETGLotInfoDetails_ds.allowEdit(false);
    }

    return ret;
}

/// <summary>
///
/// </summary>
public void clicked()
{
    super();

    if (box::yesNo('Are you sure to Lock the FGRN ?', dialogButton::Yes, 'Confirmation') == dialogButton::Yes)
    {
        ETGBinJournalLine       ETGBinJournalLine;

        select ETGBinJournalLine where ETGBinJournalLine.RecId == ETGBinLotLine.BinJournalLine;

        if(ETGBinJournalLine.RecId)
        {
            ttsbegin;
            ETGBinJournalLine.selectForUpdate(true);
            ETGBinJournalLine.BinFGRNLocked = NoYes::Yes;
            ETGBinJournalLine.doUpdate();
            ttscommit;
            ETGBinLotLine_ds.research(true);
            ETGLotInfoDetails_ds.research(true);
            Info(strFmt('%1',"FGRN has been locked successfully."));
        }
    }
}

/// <summary>
///
/// </summary>
public void clicked()
{           
    ETGBinLotLine       ETGBinLotLineloop;
    InventJournalId  TransferId;
    int loopcount=0;


    boolean  Serialenable;

    if(InventParameters::find().ETGLotTransferJrnName == '')
    {
        throw error(strFmt('%1','Define the Lot Transfer Journal Name setup in Inventory Parameter setup.'));
    }

    Serialenable=   ecoResTrackingDimensionGroupFldSetup::findByDimensionGroupFieldId(InventTable::find(ETGBinLotLine.ItemId).trackingDimensionGroup(), fieldNum(InventDim,InventSerialId)).IsActive;

    if(Serialenable == NoYes::Yes && ETGBinLotLine.InventSerialId == '')
    {
        throw error(strFmt('Serial id must be filled in.'));
    }

    super();

    for(ETGBinLotLineloop = getFirstSelection(ETGBinLotLine_ds); ETGBinLotLineloop;
    ETGBinLotLineloop = ETGBinLotLine_ds.getNext())
    {
        if(ETGBinLotLineloop.TransferJRNId == '')
        {
            loopcount++;
            if(loopcount ==1)
            {
                TransferId =  ETGGlobal::CreateTransferJournalHeaderLot(ETGBinLotLineloop.RecId);
            }
            ETGGlobal::CreateTransferJournalLineLot(ETGBinLotLineloop.RecId,loopcount,TransferId);
        }
    }

    if(TransferId)
    {
        Info(strFmt('Lot Transfer Journal %1 has been created.',TransferId));
    }
    ETGBinLotLine_ds.research(true);
}
